def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        if ratio > 1:
            priorities[i] = float('inf')
            continue
        score = 0.0
        temp_ratio = ratio
        for j in range(5):
            if temp_ratio < 0.01:
                break
            weight = 1 / (j + 1)
            increment = (np.sqrt(temp_ratio + 0.1) + np.log1p(temp_ratio)) * weight
            score += increment
            temp_ratio *= 0.85
            if score > 5:
                break
        if score < 0.5:
            score *= 2
            if ratio < 0.5:
                for k in range(2):
                    score += (0.1 / (k + 1)) * (1 - ratio)
        elif score < 2:
            score *= 7
            if capacity < item * 1.2:
                score += 3
        else:
            if ratio > 0.8:
                score *= 12
            else:
                score *= 8
        if capacity < item * 0.95:
            score += 20
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        return np.full_like(priorities, float('inf'))
    min_priority = np.min(finite_priorities)
    max_priority = np.max(finite_priorities)
    for i in range(len(priorities)):
        if not np.isfinite(priorities[i]):
            priorities[i] = min_priority * 100
        else:
            if priorities[i] == min_priority:
                priorities[i] = 0
            elif priorities[i] == max_priority:
                priorities[i] *= 1.5
            else:
                priorities[i] = (priorities[i] - min_priority) / (max_priority - min_priority) * 10
    return priorities
